// SELF-CHAT driver. The owner writes a note TO THEMSELVES starting with `sofi `
// (or Arabic `صوفي `). message.sent fires for BOTH the owner's phone-typed notes
// AND the bot's own API replies, so the `sofi`/`صوفي` prefix is the loop guard
// (bot replies never carry it). Self-chat is identified by to===from — form-
// agnostic across @lid vs @c.us, and it stops a `sofi ...` typed in someone
// else's chat from leaking a reply there.
const d = $input.first().json.data || {};
if (!d.fromMe) return [];                       // only the owner's own account
if (!d.body) return [];
if (d.type && !['text', 'chat'].includes(d.type)) return [];  // text only
if (!d.to || d.to !== d.from) return [];        // self-chat only (any address form)

const m = (d.body || '').trim().match(/^(?:sofi|صوفي)[:\s]+([\s\S]+)/i);  // prefix guard
if (!m) return [];                              // not a command (or a bot reply)
const text = m[1].trim();
if (!text) return [];

return [{ json: {
  chatId: d.chatId || d.from,                   // reply into the same self-chat
  text,
  messageId: d.id || ''
} }];

// Parse the classifier's JSON, defensively (strip stray fences, fall back
// to escalation on any parse failure — never silently drop a real ticket).
const chatId = $('Filter & Authorize').first().json.chatId;
const text = $('Filter & Authorize').first().json.text;
let parsed;
try {
  const raw = ($json.response || '').replace(/```json|```/g, '').trim();
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { trivial: false, role: 'ceo', model_tier: 'workhorse',
             reason: 'classify parse failed, escalating safe' };
}
const modelMap = { mechanical: 'haiku', workhorse: 'sonnet', gatekeeper: 'fable', deep: 'opus' };
return [{ json: {
  chatId, text,
  trivial: !!parsed.trivial,
  direct_answer: parsed.direct_answer || null,
  role: parsed.role || 'ceo',
  model: modelMap[parsed.model_tier] || 'sonnet',
  reason: parsed.reason || ''
} }];

const base = $env.SOFI_CALLBACK_BASE || 'http://127.0.0.1:5678';
const text = $json.text;
const role = $json.role;
const model = $json.model;

const command = `WhatsApp ticket, pre-classified for you (role=${role}, model=${model}):\n\n`
  + `"${text}"\n\n`
  + `Handle it end-to-end per SOFI doctrine: delegate further via the Agent tool `
  + `ONLY if this ticket genuinely needs another specialist's ownership; otherwise `
  + `do the work yourself at this role. Checkpoint any change per SOFI git discipline.\n\n`
  + `Reply format: end with a short, WhatsApp-readable summary in Arabic `
  + `(<= 1200 chars) of what you found/did and what's next — this exact text is `
  + `sent back to the owner's phone, so no markdown tables, no file trees, `
  + `just plain readable lines.`;

return [{ json: {
  role,
  project: 'PRJ-SAKK',
  command,
  model,
  mode: 'async',
  source: 'whatsapp',
  callback_url: `${base}/webhook/sofi-callback`,
  meta: { chatId: $json.chatId }
} }];
